import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Batch, incremental y streaming","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pipelines/03-batch-incremental-y-streaming.md","filePath":"data-engineering/pipelines/03-batch-incremental-y-streaming.md","lastUpdated":1782521464000}'),n={name:"data-engineering/pipelines/03-batch-incremental-y-streaming.md"};function l(r,a,o,d,c,p){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="batch-incremental-y-streaming" tabindex="-1">Batch, incremental y streaming <a class="header-anchor" href="#batch-incremental-y-streaming" aria-label="Permalink to &quot;Batch, incremental y streaming&quot;">​</a></h1><p>La forma de procesar datos depende de la latencia necesaria, el volumen, el coste y la capacidad de la fuente.</p><h2 id="batch" tabindex="-1">Batch <a class="header-anchor" href="#batch" aria-label="Permalink to &quot;Batch&quot;">​</a></h2><p>Un pipeline batch procesa datos por lotes en momentos concretos.</p><p>Ejemplos:</p><ul><li>Cierre diario de ventas.</li><li>Importacion nocturna de ficheros.</li><li>Recalculo semanal de metricas.</li><li>Carga historica de una tabla completa.</li></ul><p>Ventajas:</p><ul><li>Mas sencillo de razonar.</li><li>Facil de reprocesar.</li><li>Bueno para grandes volumenes agregados.</li><li>Coste mas predecible.</li></ul><p>Riesgos:</p><ul><li>Mayor latencia.</li><li>Ventanas de carga largas.</li><li>Fallos tardios si la validacion ocurre al final.</li></ul><h2 id="incremental" tabindex="-1">Incremental <a class="header-anchor" href="#incremental" aria-label="Permalink to &quot;Incremental&quot;">​</a></h2><p>Un pipeline incremental procesa solo datos nuevos o modificados.</p><p>Estrategias habituales:</p><ul><li>Columna <code>updated_at</code>.</li><li>Id numerico creciente.</li><li>Particiones por fecha.</li><li>Change Data Capture.</li><li>Ficheros nuevos por carpeta.</li><li>Watermarks guardados por ejecucion.</li></ul><p>Ejemplo:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ventas</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> updated_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> :last_watermark</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> updated_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> :current_watermark;</span></span></code></pre></div><p>El watermark debe persistirse cuando la carga termina correctamente. Si se guarda antes de escribir el destino, puedes perder datos en caso de fallo.</p><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><p>Un pipeline streaming procesa eventos de forma continua o casi continua.</p><p>Ejemplos:</p><ul><li>Clickstream.</li><li>Logs de aplicaciones.</li><li>Eventos de pagos.</li><li>Sensores IoT.</li><li>Cambios de inventario.</li></ul><p>Ventajas:</p><ul><li>Baja latencia.</li><li>Reaccion rapida ante eventos.</li><li>Bueno para alertas, fraude y experiencias en tiempo real.</li></ul><p>Riesgos:</p><ul><li>Mayor complejidad operativa.</li><li>Duplicados y eventos tardios.</li><li>Gestion de estado.</li><li>Orden parcial de eventos.</li></ul><h2 id="microbatch" tabindex="-1">Microbatch <a class="header-anchor" href="#microbatch" aria-label="Permalink to &quot;Microbatch&quot;">​</a></h2><p>Microbatch procesa pequenos lotes con mucha frecuencia. Es un punto intermedio entre batch y streaming.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cada 5 minutos -&gt; leer eventos nuevos -&gt; validar -&gt; escribir tabla incremental</span></span></code></pre></div><p>Es util cuando necesitas frescura razonable sin asumir toda la complejidad de un sistema streaming puro.</p><h2 id="eventos-tardios" tabindex="-1">Eventos tardios <a class="header-anchor" href="#eventos-tardios" aria-label="Permalink to &quot;Eventos tardios&quot;">​</a></h2><p>En sistemas reales, los eventos no siempre llegan en orden.</p><p>Un evento puede tener:</p><ul><li><strong>Event time:</strong> momento real en el que ocurrio.</li><li><strong>Ingestion time:</strong> momento en el que llego al sistema.</li><li><strong>Processing time:</strong> momento en el que fue procesado.</li></ul><p>Para reporting y analitica suele importar <code>event time</code>. Para operacion tecnica puede importar <code>ingestion time</code>.</p><h2 id="comparativa-rapida" tabindex="-1">Comparativa rapida <a class="header-anchor" href="#comparativa-rapida" aria-label="Permalink to &quot;Comparativa rapida&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tipo</th><th>Latencia</th><th>Complejidad</th><th>Reproceso</th><th>Caso tipico</th></tr></thead><tbody><tr><td>Batch</td><td>Alta</td><td>Baja</td><td>Sencillo</td><td>Cierre diario</td></tr><tr><td>Incremental</td><td>Media</td><td>Media</td><td>Por ventana</td><td>Tablas actualizadas</td></tr><tr><td>Microbatch</td><td>Baja-media</td><td>Media</td><td>Por lote</td><td>Sincronizacion frecuente</td></tr><tr><td>Streaming</td><td>Baja</td><td>Alta</td><td>Con offsets/eventos</td><td>Eventos en tiempo real</td></tr></tbody></table><h2 id="regla-practica" tabindex="-1">Regla practica <a class="header-anchor" href="#regla-practica" aria-label="Permalink to &quot;Regla practica&quot;">​</a></h2><p>Empieza con el modelo mas simple que cumpla la latencia real del negocio. Si un dashboard puede actualizarse cada hora, no construyas streaming solo porque suena mas moderno.</p>`,39)])])}const u=e(n,[["render",l]]);export{m as __pageData,u as default};
